mapper.select:
SELECT NVL(SUM(e.amount), 0)
FROM expense e
WHERE e.trip_id = #{tripId}

mapper.update:
UPDATE settlement
SET    amount = #{amount}
WHERE  trip_id        = #{tripId}
  AND  to_member_id   = #{toMemberId}
  AND  from_member_id = #{fromMemberId}
  AND  status        != 'COMPLETED'

mapper.select:
SELECT COUNT(*)
FROM   settlement
WHERE  trip_id        = #{tripId}
  AND  to_member_id   = #{toMemberId}
  AND  from_member_id = #{fromMemberId}
  AND  status        != 'COMPLETED'

SELECT COUNT(*)
FROM settlement
WHERE trip_id = #{tripId}
  AND from_member_id = #{memberId}
  AND status IN ('REQUESTED', 'PENDING')

mapper.insert:
INSERT INTO settlement_expense_link ( link_id, batch_id, expense_id, trip_id, created_at ) SELECT sel_link_seq.NEXTVAL, t.batch_id, t.expense_id, t.trip_id, CURRENT_TIMESTAMP FROM (
SELECT #{item.batchId} AS batch_id, #{item.expenseId} AS expense_id, #{item.tripId} AS trip_id FROM DUAL
) t WHERE NOT EXISTS ( SELECT 1 FROM settlement_expense_link sel2 WHERE sel2.batch_id = t.batch_id AND sel2.expense_id = t.expense_id )
